SELECT s.id, s.staff_id, st.Sid as staffSid, st.Sname as sname, d.Dname as dname, j.Jname as jname, s.month, s.actual_base_pay, s.overtime_pay, s.leave_days, s.leave_deduction, s.total_salary, s.status, s.calc_time, s.remarks FROM salary s LEFT JOIN staffs st ON s.staff_id = st.id LEFT JOIN departments d ON st.dept_id = d.id LEFT JOIN jobs j ON st.job_id = j.id WHERE 1=1
AND s.staff_id = #{staffId}
AND st.dept_id = #{deptId}
AND d.Dname = #{deptName}
AND DATE_FORMAT(s.month, '%Y-%m') = DATE_FORMAT(#{month}, '%Y-%m')
AND s.status = #{status}
AND st.Sname LIKE CONCAT('%', #{staffName}, '%')
AND YEAR(s.month) = #{year}
ORDER BY s.month DESC, st.Sname ASC
LIMIT #{offset}, #{limit}

